insert into offmarket.business_scores (business_id, score_run_id, layer1_base_rate, layer1_comment, layer2_sellability, layer2_comment, layer3_behavioral_trigger, layer3_comment, layer4_market_pull, layer4_comment, final_score, final_tier, final_comment, value_add_thesis, confidence, data_completeness) values
('3f48d7e8-b64e-5d8f-af95-16f82e269114', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 86, 'Dr. Kidwell earned his DDS from Baylor College of Dentistry in 1976 (~50 yrs licensed) and took over a practice his father started 50+ yrs ago — tenure proxy ~72-77, deep in the natural-exit window. Dr. Derek Albus (Baylor 1998) is the long-time associate and obvious successor, so an exit is plausible and structured. Medium-low confidence (proxy age, but strongly corroborated by ''patient since 1958'').', 82, 'Strong asset: a 60+-yr Preston Center (75225) preventive/restorative practice with an in-house lab (''The Lab Guys''), 2 providers, ~9 staff, an extraordinarily deep loyal base (patients since the 1950s-60s), clean record — very sellable and bankable in one of Dallas''s wealthiest catchments.', 62, 'Coasting tells: founder well past retirement age, dated web brand, no visible recent expansion beyond the existing associate — but with Dr. Albus already in place and an in-house lab being actively run, it''s not strongly disengaged. Moderate L3.', 88, 'Preston Center / Park Cities (75225) is a top buy-side target; a 60-yr practice with a built-in successor and an in-house lab is a textbook associate-buy-in or premium SBA-financed acquisition. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 78, 'B_forward', 'Dr. (R. Bruce) Kidwell (with Dr. Derek M. Albus), ~73 (license_tenure_proxy), runs Kidwell & Albus Preventive and Restorative Dentistry of Dallas in Dallas, Dallas County. Dr. Kidwell earned his DDS from Baylor College of Dentistry in 1976 (~50 yrs licensed) and took over a practice his father started 50+ yrs ago — tenure proxy ~72-77, deep in the natural-exit window. Dr. Derek Albus (Baylor 1998) is the long-time associate and obvious successor, so an exit is plausible and structured. Medium-low confidence (proxy age, but strongly corroborated by ''patient since 1958''). Coasting tells: founder well past retirement age, dated web brand, no visible recent expansion beyond the existing associate — but with Dr. Albus already in place and an in-house lab being actively run, it''s not strongly disengaged. Moderate L3. Preston Center / Park Cities (75225) is a top buy-side target; a 60-yr practice with a built-in successor and an in-house lab is a textbook associate-buy-in or premium SBA-financed acquisition. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 78/100. Tier B — hand to the buyer / searcher community.', 'Formalize the Albus buy-in, AI front desk + recall automation + online scheduling + modern PMS + automated reviews, and keep/monetize the in-house lab — a credible 1.5-2x EBITDA path over 18-24 months in a premium catchment.', 'low', 0.5),
('65297a85-4c48-5603-9582-dbad16806b11', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 58, 'Dr. Leftwich (Texas A&M / Baylor College of Dentistry DDS) runs a long-established Lakewood practice and added an associate (Dr. Jake Hornberger) in August 2020 — the associate hire 4-5 yrs out is a classic ''building a transition vehicle'' move; tenure proxy puts Leftwich ~54-58. Medium-low confidence (proxy age).', 76, 'Clean, well-regarded Lakewood (75214) general/cosmetic family practice, 2 providers, ~8 staff, recurring base, Super Dentists listing, clean record — a real, financeable, attractive practice in a desirable catchment.', 56, 'Coasting tells: dated-ish web brand, no recent expansion beyond the new associate — but adding an associate is itself a forward-looking move, and the owner is only ~56. Moderate L3 — re-score as the buy-in matures.', 86, 'Lakewood / East Dallas (75214) is a desirable, in-demand catchment; a 2-provider family practice with a built-in successor is a textbook associate-buy-in. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 66, 'B_forward', 'Dr. Jay Leftwich (with Dr. Jake Hornberger), ~56 (license_tenure_proxy), runs Leftwich + Hornberger Dentistry (Jay Leftwich, DDS) in Dallas, Dallas County. Dr. Leftwich (Texas A&M / Baylor College of Dentistry DDS) runs a long-established Lakewood practice and added an associate (Dr. Jake Hornberger) in August 2020 — the associate hire 4-5 yrs out is a classic ''building a transition vehicle'' move; tenure proxy puts Leftwich ~54-58. Medium-low confidence (proxy age). Coasting tells: dated-ish web brand, no recent expansion beyond the new associate — but adding an associate is itself a forward-looking move, and the owner is only ~56. Moderate L3 — re-score as the buy-in matures. Lakewood / East Dallas (75214) is a desirable, in-demand catchment; a 2-provider family practice with a built-in successor is a textbook associate-buy-in. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 66/100. Tier B — hand to the buyer / searcher community.', 'Formalize the Hornberger buy-in; AI front desk + recall automation + online scheduling + modern PMS + automated reviews — 2-year EBITDA upside. Re-score in ~12-18 months.', 'low', 0.45),
('6277e1ba-c7c3-5ded-a34e-4d67c2b01ab8', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 48, 'The practice has run since 1972 (~54 yrs; founder Dr. William Andress), now carried by Drs. Holmes, Revel and Lowery — but the current dentists'' individual ages and tenures aren''t verified, so the base rate is moderate/uncertain. Whoever is the senior partner may be near exit; needs a TSBDE check. Low confidence.', 76, 'A real, long-established (54-yr) Pasadena (77504) general/cosmetic/restorative practice with 3 dentists, ~12 staff, a deep multigenerational recurring base, clean record — clearly financeable and of meaningful size.', 44, 'A 3-dentist practice that''s stayed independent for 54 yrs could be coasting (aging senior partner) or actively run by younger partners — no decline stack verified. Moderate-low L3, low confidence.', 82, 'Pasadena / SE Houston has steady DSO interest; a 54-yr, 3-dentist practice with a deep base is a strong roll-up target. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 59, 'C_watch', 'Drs. Holmes, Revel & Lowery, ~55 (license_tenure_proxy), runs Pasadena Family Dentistry (Holmes, Revel & Lowery, DDS) in Pasadena, Harris County. The practice has run since 1972 (~54 yrs; founder Dr. William Andress), now carried by Drs. Holmes, Revel and Lowery — but the current dentists'' individual ages and tenures aren''t verified, so the base rate is moderate/uncertain. Whoever is the senior partner may be near exit; needs a TSBDE check. Low confidence. A 3-dentist practice that''s stayed independent for 54 yrs could be coasting (aging senior partner) or actively run by younger partners — no decline stack verified. Moderate-low L3, low confidence. Pasadena / SE Houston has steady DSO interest; a 54-yr, 3-dentist practice with a deep base is a strong roll-up target. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 59/100. Tier C — re-score in ~90 days.', 'Pending which partner is the seller: standard recall/AI/scheduling/PMS stack across the practice. Verify partner ages/tenures before acting.', 'low', 0.35),
('90aefa1b-1f59-5003-a2b4-e985d916fc35', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 84, 'Dr. Schneider earned his first dental degree in 1981 (Colombia), a prosthodontics certificate in 1987, and his DDS in 1989 from UT-Houston Health Science Center — ~37-45 yrs in dentistry; tenure proxy ~65-68, in the natural-exit window; solo specialist with no associate. Medium-low confidence (proxy age).', 72, 'Clean solo prosthodontic practice (implants/dentures/cosmetic/TMJ/full restorations) in the Post Oak/Galleria corridor (77027), high-value case mix, recurring base, clean record — a sellable, bankable specialty practice. Prosthodontics is a narrower buyer pool than general dentistry, which caps it modestly.', 64, 'Coasting tells: solo specialist with no associate, dated web brand, no visible recent expansion or hiring, owner near a natural exit. Healthy, disengaged-growth — not distress.', 80, 'Post Oak/Galleria Houston (77027) is a premium corridor; prosthodontic/implant practices are SBA-financeable and sought by DSOs and implant-focused groups, though the specialty narrows demand vs. a general practice. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 74, 'B_forward', 'Dr. Walter W. Schneider, ~67 (license_tenure_proxy), runs Walter Schneider, D.D.S., P.A. in Houston, Harris County. Dr. Schneider earned his first dental degree in 1981 (Colombia), a prosthodontics certificate in 1987, and his DDS in 1989 from UT-Houston Health Science Center — ~37-45 yrs in dentistry; tenure proxy ~65-68, in the natural-exit window; solo specialist with no associate. Medium-low confidence (proxy age). Coasting tells: solo specialist with no associate, dated web brand, no visible recent expansion or hiring, owner near a natural exit. Healthy, disengaged-growth — not distress. Post Oak/Galleria Houston (77027) is a premium corridor; prosthodontic/implant practices are SBA-financeable and sought by DSOs and implant-focused groups, though the specialty narrows demand vs. a general practice. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 74/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + recall + online scheduling + modern PMS + automated reviews; bring in a general-dentist associate to feed the prosthodontic case mix and de-risk the transition — credible EBITDA uplift over 18-24 months.', 'low', 0.45),
('ac8d136a-5b85-58c3-b444-fb7e9f35d2b6', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 46, 'The Galleria-area cosmetic practice has operated since 1989 (~37 yrs), but Dr. Canto (UT Dental Branch Houston DDS) appears mid-career and may be a more recent owner of the long-standing practice — her individual tenure isn''t verified, so the base rate is moderate/uncertain. Low confidence; needs a TSBDE check.', 74, 'A real, award-winning Galleria (77056) cosmetic practice with a 37-yr brand history, recurring base, ~7 staff, clean record — financeable in a premium niche; the unknown is the owner''s age/tenure.', 42, 'A cosmetic practice still actively marketing and racking up awards isn''t obviously coasting; no decline stack verified. Moderate-low L3, low confidence.', 86, 'Galleria Houston cosmetic practice — premium positioning, strong DSO and high-net-worth-dentist demand. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 58, 'C_watch', 'Dr. Amanda Canto, ~52 (license_tenure_proxy), runs Cosmetic Dentists of Houston (Amanda Canto, DDS) in Houston, Harris County. The Galleria-area cosmetic practice has operated since 1989 (~37 yrs), but Dr. Canto (UT Dental Branch Houston DDS) appears mid-career and may be a more recent owner of the long-standing practice — her individual tenure isn''t verified, so the base rate is moderate/uncertain. Low confidence; needs a TSBDE check. A cosmetic practice still actively marketing and racking up awards isn''t obviously coasting; no decline stack verified. Moderate-low L3, low confidence. Galleria Houston cosmetic practice — premium positioning, strong DSO and high-net-worth-dentist demand. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 58/100. Tier C — re-score in ~90 days.', 'Pending owner verification: AI front desk + concierge recall + online scheduling + modern PMS + automated reviews + structured high-value cosmetic-case marketing. Verify owner age/tenure before acting.', 'low', 0.3),
('b44d39e8-4ad3-5a0e-8ef4-fa2c04ba864f', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 20, 'Practice itself is ~30 yrs old, but Dr. Pickei only bought it in July 2021 (~5 yrs as owner) from the long-tenured Dr. James M. Seale and is clearly early-career — far from a natural-exit window. Low L1; barely above the <5-yr gate on practice age (the practice is older, so no cap, but the owner relationship is brand new).', 68, 'Clean West-U-area (77025) general/cosmetic/implant practice with a 30-yr history and an inherited recurring base, ~6 staff, clean record — a real, financeable practice; the owner just isn''t a seller.', 22, 'Not coasting — new energetic owner, active marketing, fresh reviews. Low L3.', 84, 'West University Place Houston (77025) is a premium catchment with strong DSO interest, but a brand-new owner isn''t a target. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 42, 'D_pass', 'Dr. Ross Pickei, ~40 (license_tenure_proxy), runs West University Dentistry (Ross Pickei, DDS) in Houston, Harris County. Practice itself is ~30 yrs old, but Dr. Pickei only bought it in July 2021 (~5 yrs as owner) from the long-tenured Dr. James M. Seale and is clearly early-career — far from a natural-exit window. Low L1; barely above the <5-yr gate on practice age (the practice is older, so no cap, but the owner relationship is brand new). Not coasting — new energetic owner, active marketing, fresh reviews. Low L3. West University Place Houston (77025) is a premium catchment with strong DSO interest, but a brand-new owner isn''t a target. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 42/100. Tier D — pass for now.', 'N/A near-term — owner just bought it. Watch.', 'low', 0.4),
('9d7e1093-ef67-5a50-8804-02af7fcf999c', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 40, 'Practice founded 2007 (~19 yrs); two partners (Dr. Zavala = owner) whose individual ages aren''t verified but who appear mid-career — tenure proxy ~46-52, not at a natural-exit window. Williamson County, adjacent to Travis — deprioritized. Low-medium L1.', 72, 'Clean ~19-yr Round Rock (78664) general/implant/Invisalign practice, 2 providers, ~8 staff, good reviews (41 Yelp), recurring base, clean record — a real, financeable practice in a high-growth suburb.', 38, 'Not strongly coasting — 2 providers, active marketing, mid-career partners. Low-moderate L3.', 82, 'Round Rock / Williamson County is a high-growth Austin-metro suburb with active DSO interest; just outside the core 3 counties. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 54, 'C_watch', 'Drs. John Zavala & Fredrick R. Lewcock, ~50 (license_tenure_proxy), runs Old Settlers Dental (John Zavala, DDS & Fredrick R. Lewcock, DDS) in Round Rock, Williamson County. Practice founded 2007 (~19 yrs); two partners (Dr. Zavala = owner) whose individual ages aren''t verified but who appear mid-career — tenure proxy ~46-52, not at a natural-exit window. Williamson County, adjacent to Travis — deprioritized. Low-medium L1. Not strongly coasting — 2 providers, active marketing, mid-career partners. Low-moderate L3. Round Rock / Williamson County is a high-growth Austin-metro suburb with active DSO interest; just outside the core 3 counties. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 54/100. Tier C — re-score in ~90 days.', 'AI front desk + recall + online scheduling + modern PMS + automated reviews — incremental EBITDA over 2 yrs; better as a ''forward'' than a near-term acquisition. Re-score in ~3 yrs.', 'low', 0.4),
('a1093990-3034-5194-b4ab-7bd057f2b5c7', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 45, 'Principal dentist''s age, tenure, and practice age not verified — treat L1 as neutral/uncertain. Low confidence; needs a TSBDE issue-date check.', 72, 'A real, operating Far North Dallas (75252) general/family practice on the Preston Rd corridor, recurring base, ~6 staff — financeable, pending verification of size, age, and ownership.', 42, 'No verified coasting tells; reasonably maintained presence. Moderate-low L3, low confidence.', 85, 'Far North Dallas / Preston Rd (75252) is a hot DSO/PE catchment. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 57, 'C_watch', 'Owner, age unknown, runs Preston Smiles Family Dentistry in Dallas, Dallas County. Principal dentist''s age, tenure, and practice age not verified — treat L1 as neutral/uncertain. Low confidence; needs a TSBDE issue-date check. No verified coasting tells; reasonably maintained presence. Moderate-low L3, low confidence. Far North Dallas / Preston Rd (75252) is a hot DSO/PE catchment. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 57/100. Tier C — re-score in ~90 days.', 'Pending verification: standard recall/AI/scheduling/PMS stack. Verify owner age and practice age before acting.', 'low', 0.25)
